import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Dashboard() {
  const [salesPerRestaurant, setSalesPerRestaurant] = useState([]);
  const [mostOrderedItems, setMostOrderedItems] = useState([]);
  const [avgOrderValue, setAvgOrderValue] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [salesRes, itemsRes, avgRes] = await Promise.all([
          axios.get('http://localhost:5000/analytics/sales-per-restaurant'),
          axios.get('http://localhost:5000/analytics/most-ordered-items'),
          axios.get('http://localhost:5000/analytics/average-order-value')
        ]);
        setSalesPerRestaurant(salesRes.data);
        setMostOrderedItems(itemsRes.data);
        setAvgOrderValue(avgRes.data);
      } catch (error) {
        console.error("Error fetching analytics:", error);
      }
    };
    fetchData();
  }, []);

  return (
    <div>
      <h1>DASHBOARD ANALYTICS</h1>

      {avgOrderValue && (
        <div className="analytics-grid">
          <div className="analytic-card">
            <p>AVERAGE ORDER VALUE</p>
            <div className="value">${avgOrderValue.avgOrderValue.toFixed(2)}</div>
            <p style={{ opacity: 0.6 }}>TOTAL ORDERS: {avgOrderValue.totalOrders}</p>
          </div>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '4rem', marginTop: '4rem' }}>
        <div>
          <h2>SALES PER RESTAURANT</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
            <thead>
              <tr style={{ borderBottom: '2px solid black' }}>
                <th style={{ padding: '1rem 0' }}>RESTAURANT</th>
                <th>SALES</th>
                <th>ORDERS</th>
              </tr>
            </thead>
            <tbody>
              {salesPerRestaurant.map(item => (
                <tr key={item._id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '1rem 0', fontWeight: 700 }}>{item.restaurantName}</td>
                  <td>${item.totalSales.toFixed(2)}</td>
                  <td>{item.orderCount}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div>
          <h2>MOST ORDERED ITEMS</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
            <thead>
              <tr style={{ borderBottom: '2px solid black' }}>
                <th style={{ padding: '1rem 0' }}>ITEM</th>
                <th>QUANTITY</th>
                <th>REVENUE</th>
              </tr>
            </thead>
            <tbody>
              {mostOrderedItems.map(item => (
                <tr key={item._id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '1rem 0', fontWeight: 700 }}>{item._id}</td>
                  <td>{item.totalQuantity}</td>
                  <td>${item.totalRevenue.toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
